type Home_Position is record
   Latitude   : Interfaces.Integer_32;
   Longitude  : Interfaces.Integer_32;
   Altitude   : Interfaces.Integer_32;
   X          : Raw_Float;
   Y          : Raw_Float;
   Z          : Raw_Float;
